import React,{useEffect,useMemo,useState} from "react";import{BriefcaseBusiness,CalendarDays,Search}from"lucide-react";import{vendorAPI,formatDate,safeArray}from"../../services/api.js";import{routeLabel,moveTypeLabel}from"../../utils/mappers.js";import{useToast}from"../../components/ui/Toast.jsx";import Modal from"../../components/ui/Modal.jsx";import{CardPanel,DetailsGrid,PageHeader,StatusPill}from"../../components/ui/PortalUI.jsx";
export default function VendorAssignedJobsPage(){const{showToast}=useToast();const[jobs,setJobs]=useState([]);const[keyword,setKeyword]=useState("");const[selected,setSelected]=useState(null);useEffect(()=>{(async()=>{try{setJobs(safeArray(await vendorAPI.leads()))}catch(e){showToast(e.message,"error")}})()},[]);const rows=useMemo(()=>jobs.filter((x)=>{const m=x.move||x;return[m.job_id,m.pickup_postcode,m.delivery_postcode,m.status,x.status].filter(Boolean).join(" ").toLowerCase().includes(keyword.toLowerCase())}),[jobs,keyword]);return <div className="page-wrap"><PageHeader icon={BriefcaseBusiness} title="Assigned Jobs" subtitle="All assigned jobs from AnQ Movers." search={keyword} onSearch={setKeyword} placeholder="Search assigned jobs..."/><CardPanel title="Assigned Jobs"><div className="table-scroll"><table><thead><tr><th>Job ID</th><th>Move Type</th><th>Route</th><th>Date</th><th>Assignment</th><th>Status</th><th>Action</th></tr></thead><tbody>{rows.map((x)=>{const m=x.move||x;return<tr key={x.id||m.id}><td><b>{m.job_id}</b></td><td>{moveTypeLabel(m.move_type)}</td><td>{routeLabel(m.pickup_postcode,m.delivery_postcode)}</td><td><CalendarDays size={13}/>{formatDate(m.moving_date)}</td><td>{x.status||"assigned"}</td><td><StatusPill value={m.status}/></td><td><button className="tiny-btn" onClick={()=>setSelected(x)}>View</button></td></tr>})}</tbody></table>{!rows.length?<div className="empty-state">No assigned jobs found.</div>:null}</div></CardPanel><Modal open={!!selected} title="Assigned Job Details" onClose={()=>setSelected(null)} size="lg"><DetailsGrid rows={[["Job ID",(selected?.move||selected)?.job_id],["Move Type",moveTypeLabel((selected?.move||selected)?.move_type)],["Route",routeLabel((selected?.move||selected)?.pickup_postcode,(selected?.move||selected)?.delivery_postcode)],["Move Date",formatDate((selected?.move||selected)?.moving_date)],["Property",`${(selected?.move||selected)?.property_size||"—"} / ${(selected?.move||selected)?.property_type||"—"}`],["Contact",(selected?.move||selected)?.contact_released?"Released":"Hidden until deposit"]]}/></Modal></div>}
